"use client";

import { useMemo, useState } from "react";
import { DeptHeader } from "@/components/shared/DeptHeader";
import { AIStrip } from "@/components/shared/AIStrip";
import { PeriodTabs } from "@/components/shared/PeriodTabs";
import { BridgePrimaryButton } from "@/features/bridge/components/BridgePrimaryButton";
import {
  recurringItems,
  recurringAI,
  FREQ_ORDER,
  type RecurringItem,
} from "@/features/finance/api/finance-recurring-data";
import "./recurring.css";

const PERIOD_LABELS = ["This month", "Last quarter avg", "Year to date"];
type SortKey = "name" | "freq" | "base" | "actual" | "var" | "next" | "status";
type FilterKey = "all" | "rose" | "waste" | "paused";
const DEFAULT_DIR: Record<SortKey, "asc" | "desc"> = {
  name: "asc",
  freq: "asc",
  base: "desc",
  actual: "desc",
  var: "desc",
  next: "asc",
  status: "asc",
};
const PAGE_SIZE = 20;

const fmt = (v: number) => {
  const s = v < 0 ? "-$" : "$";
  return s + Math.abs(Math.round(v)).toLocaleString("en-US");
};
const fmtK = (v: number) => {
  const s = v < 0 ? "-$" : "$";
  return s + Math.round(Math.abs(v) / 1000) + "K";
};

const ArrowIcon = (
  <svg
    viewBox="0 0 24 24"
    fill="none"
    stroke="currentColor"
    strokeWidth="2"
    strokeLinecap="round"
    strokeLinejoin="round"
  >
    <line x1="5" y1="12" x2="19" y2="12" />
    <polyline points="12 5 19 12 12 19" />
  </svg>
);

export default function RecurringPage() {
  const [periodIdx, setPeriodIdx] = useState(0);
  const [sortKey, setSortKey] = useState<SortKey>("var");
  const [sortDir, setSortDir] = useState<"asc" | "desc">("desc");
  const [filterKey, setFilterKey] = useState<FilterKey>("all");
  const [search, setSearch] = useState("");
  const [shown, setShown] = useState(PAGE_SIZE);

  // every item gets a derived varAmt; paused = 0
  const items = useMemo(
    () =>
      recurringItems.map((it) => ({
        ...it,
        varAmt: it.status === "paused" ? 0 : it.actual - it.base,
      })),
    [],
  );

  const filtered = useMemo(() => {
    let list = items.slice();
    if (filterKey === "rose") list = list.filter((i) => i.rose);
    else if (filterKey === "waste") list = list.filter((i) => i.waste);
    else if (filterKey === "paused") list = list.filter((i) => i.status === "paused");
    if (search) {
      const q = search.toLowerCase();
      list = list.filter((i) => (i.name + " " + i.cat).toLowerCase().includes(q));
    }
    const dir = sortDir === "asc" ? 1 : -1;
    list.sort((a, b) => {
      if (sortKey === "name") return dir * a.name.localeCompare(b.name);
      if (sortKey === "freq") return dir * (FREQ_ORDER[a.freq] - FREQ_ORDER[b.freq]);
      if (sortKey === "next") return dir * String(a.next).localeCompare(String(b.next));
      if (sortKey === "status") return dir * a.status.localeCompare(b.status);
      if (sortKey === "var") return dir * (a.varAmt - b.varAmt);
      return dir * ((a[sortKey] as number) - (b[sortKey] as number));
    });
    return list;
  }, [items, filterKey, search, sortKey, sortDir]);

  const visible = filtered.slice(0, shown);
  const total = filtered.length;
  const remaining = Math.max(0, total - shown);
  const nextChunk = Math.min(PAGE_SIZE, remaining);

  // foot sums — over the entire filtered set
  const activeFiltered = filtered.filter((i) => i.status !== "paused");
  const sumBase = activeFiltered.reduce((s, i) => s + i.base, 0);
  const sumActual = activeFiltered.reduce((s, i) => s + i.actual, 0);
  const sumVar = sumActual - sumBase;

  // header metrics — over the whole dataset
  const hdrActive = items.filter((i) => i.status !== "paused");
  const hdrBase = hdrActive.reduce((s, i) => s + i.base, 0);
  const hdrActual = hdrActive.reduce((s, i) => s + i.actual, 0);
  const hdrVar = hdrActual - hdrBase;
  const hdrPct = (hdrVar / hdrBase) * 100;
  const rose = items.filter((i) => i.rose).length;
  const paused = items.filter((i) => i.status === "paused").length;

  // category sidebar
  const catRows = useMemo(() => {
    const cats: Record<string, { base: number; actual: number }> = {};
    items
      .filter((i) => i.status !== "paused")
      .forEach((i) => {
        if (!cats[i.cat]) cats[i.cat] = { base: 0, actual: 0 };
        cats[i.cat].base += i.base;
        cats[i.cat].actual += i.actual;
      });
    const arr = Object.entries(cats).map(([name, v]) => ({
      name,
      base: v.base,
      actual: v.actual,
      varAmt: v.actual - v.base,
    }));
    arr.sort((a, b) => b.base - a.base);
    return arr;
  }, [items]);
  const catMax = Math.max(...catRows.map((c) => c.base), 1);
  const catTotal = catRows.reduce((s, c) => s + c.base, 0);

  const onSort = (k: SortKey) => {
    if (k === sortKey) setSortDir(sortDir === "asc" ? "desc" : "asc");
    else {
      setSortKey(k);
      setSortDir(DEFAULT_DIR[k]);
    }
    setShown(PAGE_SIZE);
  };
  const setFilter = (k: FilterKey) => {
    setFilterKey(k);
    setShown(PAGE_SIZE);
  };

  return (
    <div className="finance-recurring-page">
      <DeptHeader
        dept="finance"
        title="Recurring Costs"
        meta={
          <>
            <span className="live">Live</span> · What you&rsquo;re committed to every month — and what you can cut
          </>
        }
        actions={
          <>
            <button className="btn-util">Export</button>
            <BridgePrimaryButton dept="finance">Review in Bridge →</BridgePrimaryButton>
          </>
        }
      />

      <PeriodTabs labels={PERIOD_LABELS} activeIndex={periodIdx} onChange={setPeriodIdx} />

      {/* Metric strip */}
      <div className="metric-strip">
        <div className="metric">
          <div className="metric-l">Monthly base</div>
          <div className="metric-v">{fmt(hdrBase)}</div>
          <div className="metric-s flat">total committed</div>
        </div>
        <div className="metric">
          <div className="metric-l">Last month actual</div>
          <div className="metric-v">{fmt(hdrActual)}</div>
          <div className={`metric-s ${hdrVar > 0 ? "down" : hdrVar < 0 ? "up" : "flat"}`}>
            {hdrVar >= 0 ? `${fmt(hdrVar)} over base` : `${fmt(-hdrVar)} under base`}
          </div>
        </div>
        <div className="metric">
          <div className="metric-l">Variance</div>
          <div className={`metric-v ${hdrVar > 0 ? "red" : hdrVar < 0 ? "green" : ""}`}>
            {(hdrVar >= 0 ? "+" : "−") + Math.abs(hdrPct).toFixed(1)}
            <span className="u">%</span>
          </div>
          <div className={`metric-s ${hdrVar > 0 ? "down" : "flat"}`}>
            {rose} service{rose !== 1 ? "s" : ""} rose
          </div>
        </div>
        <div className="metric">
          <div className="metric-l">Active entries</div>
          <div className="metric-v">
            {items.length - paused}
            <span className="u"> / {items.length}</span>
          </div>
          <div className="metric-s flat">{paused} paused</div>
        </div>
      </div>

      <AIStrip
        label={recurringAI.label}
        meta={recurringAI.meta}
        cards={recurringAI.cards}
      />

      {/* Tools */}
      <div className="ldg-tools">
        <div className="pt-search">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8">
            <circle cx="11" cy="11" r="7" />
            <path d="M21 21l-4.3-4.3" />
          </svg>
          <input
            type="text"
            placeholder="Search services, categories..."
            value={search}
            onChange={(e) => {
              setSearch(e.target.value);
              setShown(PAGE_SIZE);
            }}
          />
          <span className="search-count">{items.length} entries</span>
        </div>
        <div className="filters">
          {(
            [
              ["all", "All"],
              ["rose", "Rose"],
              ["waste", "Unused"],
              ["paused", "Paused"],
            ] as [FilterKey, string][]
          ).map(([k, label]) => (
            <button
              key={k}
              className={`fchip${filterKey === k ? " active" : ""}`}
              onClick={() => setFilter(k)}
              type="button"
            >
              {label}
            </button>
          ))}
        </div>
      </div>

      <div className="rc-grid">
        <div className="rtable">
          <RTHead sortKey={sortKey} sortDir={sortDir} onSort={onSort} />

          {visible.length === 0 ? (
            <div className="rt-empty">No services match this filter</div>
          ) : (
            visible.map((it, i) => <RTRow key={it.name + i} it={it} />)
          )}

          {remaining > 0 && (
            <div className="rt-more">
              <button
                className="lm-btn"
                onClick={() => setShown(shown + PAGE_SIZE)}
                type="button"
              >
                Load {nextChunk} more
              </button>
              <span className="lm-note">
                Showing {visible.length} of {total}
              </span>
            </div>
          )}

          <div className="rtable-foot">
            <span className="foot-note">
              {total === items.length
                ? `All ${items.length} entries`
                : `${total} of ${items.length} entries`}
            </span>
            <div className="foot-sums">
              <div className="foot-sum">
                <span className="l">Monthly base</span>
                <span className="v">{fmtK(sumBase)}</span>
              </div>
              <div className="foot-sum">
                <span className="l">Last actual</span>
                <span className="v">{fmtK(sumActual)}</span>
              </div>
              <div className="foot-sum">
                <span className="l">Variance</span>
                <span className={`v ${sumVar > 0 ? "red" : sumVar < 0 ? "green" : ""}`}>
                  {(sumVar > 0 ? "+" : "") + fmt(sumVar)}
                </span>
              </div>
            </div>
          </div>
        </div>

        <div className="cat-card">
          <div className="cat-title">By category</div>
          <div className="cat-sub">Share of monthly commitment</div>
          <div>
            {catRows.map((c) => {
              const pct = Math.max(2, (c.base / catMax) * 100);
              const vcls =
                c.varAmt > 0 ? "up" : c.varAmt < 0 ? "down" : "flat";
              const vtxt =
                c.varAmt > 0
                  ? "+" + fmt(c.varAmt)
                  : c.varAmt < 0
                  ? fmt(c.varAmt)
                  : "on base";
              return (
                <div key={c.name} className="crow">
                  <div className="crow-top">
                    <span className="crow-name">{c.name}</span>
                    <span className="crow-fig">
                      <span className="crow-amt">{fmt(c.base)}</span>
                      <span className={`crow-var ${vcls}`}>{vtxt}</span>
                    </span>
                  </div>
                  <div className="cbar">
                    <div className="cbar-fill" style={{ width: `${pct}%` }} />
                  </div>
                </div>
              );
            })}
          </div>
          <div className="cat-foot">
            <span className="l">Total / mo</span>
            <span className="v">{fmt(catTotal)}</span>
          </div>
        </div>
      </div>
    </div>
  );
}

interface RTHeadProps {
  sortKey: SortKey;
  sortDir: "asc" | "desc";
  onSort: (k: SortKey) => void;
}

function RTHead({ sortKey, sortDir, onSort }: RTHeadProps) {
  const cell = (k: SortKey, label: string, num = false) => {
    const active = sortKey === k;
    return (
      <button
        type="button"
        className={`th${num ? " num" : ""}${active ? " active" : ""}`}
        onClick={() => onSort(k)}
      >
        {label}
        <i className="ar">{active && sortDir === "desc" ? "↓" : "↑"}</i>
      </button>
    );
  };
  return (
    <div className="rt-head">
      {cell("name", "Service")}
      {cell("freq", "Frequency", true)}
      {cell("base", "Base", true)}
      {cell("actual", "Last actual", true)}
      {cell("var", "Variance", true)}
      {cell("next", "Next due", true)}
      {cell("status", "Status", true)}
    </div>
  );
}

function RTRow({ it }: { it: RecurringItem & { varAmt: number } }) {
  const flag =
    it.waste || it.varAmt > 0 ? "var(--loss)" : "transparent";
  const varCls =
    it.status === "paused"
      ? "flat"
      : it.varAmt > 0
      ? "up"
      : it.varAmt < 0
      ? "down"
      : "flat";
  const varText =
    it.status === "paused"
      ? "—"
      : it.varAmt > 0
      ? "+" + fmt(it.varAmt)
      : it.varAmt < 0
      ? fmt(it.varAmt)
      : "$0";
  const actionLabel = it.waste ? "Cancel" : it.varAmt > 0 ? "Review" : "Manage";

  return (
    <div
      className={`rt-row${it.status === "paused" ? " paused" : ""}`}
      style={{ ["--flag" as string]: flag } as React.CSSProperties}
    >
      <div className="rname">
        <span className="nm">{it.name}</span>
        {it.waste ? (
          <span className="ctag waste">Unused 60d</span>
        ) : (
          <span className="ctag">{it.cat}</span>
        )}
      </div>
      <div className="freq">{it.freq}</div>
      <div className="num">{fmt(it.base)}</div>
      <div className={`num${it.status === "paused" ? " muted" : ""}`}>
        {it.status === "paused" ? "—" : fmt(it.actual)}
      </div>
      <div className={`var-cell ${varCls}`}>{varText}</div>
      <div className="next">
        {it.next}
        <span className="nd">{it.status === "paused" ? "paused" : "next due"}</span>
      </div>
      <div className="statusc">
        {it.status === "active" ? (
          <span className="sbadge active">
            <span className="sd" />
            Active
          </span>
        ) : (
          <span className="sbadge paused">
            <span className="sd" />
            Paused
          </span>
        )}
      </div>
      <button className="rt-bridge" type="button">
        {actionLabel} {ArrowIcon}
      </button>
    </div>
  );
}
