/**
 * Mock data for Finance · Recurring Costs.
 *
 * Sortable, filterable, searchable table of every monthly commitment, plus
 * a sidebar showing share-by-category. Header metrics derive from the
 * same items[] array so the strip and the foot can never drift.
 */

export type Frequency = "Weekly" | "Monthly" | "Annual";
export type Status = "active" | "paused";
export type Category =
  | "Rent & Utilities"
  | "Salaries & Wages"
  | "Software & Subscriptions"
  | "Professional Services"
  | "Insurance";

export interface RecurringItem {
  name: string;
  cat: Category;
  freq: Frequency;
  /** Monthly-equivalent base in USD. */
  base: number;
  /** Last actual monthly-equivalent in USD (0 when paused). */
  actual: number;
  next: string;
  status: Status;
  /** Cost rose from base this month. */
  rose?: boolean;
  /** Service has been unused for 60+ days. */
  waste?: boolean;
}

